export interface BrandProduct {
  name: string;
  size?: string;
  image?: string;
}

export interface Brand {
  slug: string;
  name: string;
  origin: string;
  category: string;
  description: string;
  website?: string;
  image: string;
  products: BrandProduct[];
}

const slugify = (s: string) =>
  s
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/(^-|-$)/g, "");

